function sameComposition(a, b) {
  if (a.length !== b.length) return false;   // quick reject
  const counts = new Map();
  for (const ch of a) {
    counts.set(ch, (counts.get(ch) ?? 0) + 1);
  }
  for (const ch of b) {
    const c = counts.get(ch);
    if (!c) return false;        // char absent in a, or already used up
    counts.set(ch, c - 1);
  }
  return true;                   // every char in b canceled one in a
}

// sameComposition('teacher', 'cheater') -> true
// sameComposition('Hello', 'hello')     -> false (case-sensitive)
// sameComposition('aab', 'abb')         -> false

function pairSum(sorted, target) {
  let lo = 0, hi = sorted.length - 1;
  while (lo < hi) {
    const sum = sorted[lo] + sorted[hi];
    if (sum === target) return [sorted[lo], sorted[hi]];
    if (sum < target) lo++;   // too small: raise the low value
    else hi--;                // too large: lower the high value
  }
  return null;                // pointers crossed with no match
}

// pairSum([1, 2, 4, 7, 11, 15], 15) -> [4, 11]
// pairSum([2, 3, 5, 8], 20)         -> null
// pairSum([-3, -1, 0, 2, 6], -1)    -> [-3, 2]

function longestWithKDistinct(s, k) {
  if (k === 0) return 0;
  const counts = new Map();   // char -> occurrences inside the window
  let left = 0, best = 0;
  for (let right = 0; right < s.length; right++) {
    const ch = s[right];
    counts.set(ch, (counts.get(ch) ?? 0) + 1);   // grow window
    while (counts.size > k) {                     // too many distinct
      const leftCh = s[left];
      const c = counts.get(leftCh) - 1;
      if (c === 0) counts.delete(leftCh);         // char fully left window
      else counts.set(leftCh, c);
      left++;
    }
    best = Math.max(best, right - left + 1);
  }
  return best;
}

// longestWithKDistinct('eceba', 2)   -> 3 ('ece')
// longestWithKDistinct('aabbcc', 1)  -> 2 ('aa')
// longestWithKDistinct('abc', 0)     -> 0

function minShelfCapacity(weights, maxShelves) {
  const shelvesNeeded = (cap) => {
    let shelves = 1, load = 0;
    for (const w of weights) {
      if (w > cap) return Infinity;      // a single item cannot fit
      if (load + w > cap) { shelves++; load = 0; } // open a new shelf
      load += w;
    }
    return shelves;
  };

  let lo = Math.max(...weights);          // must at least fit the heaviest
  let hi = weights.reduce((a, b) => a + b, 0); // everything on one shelf
  while (lo < hi) {
    const mid = lo + ((hi - lo) >> 1);
    if (shelvesNeeded(mid) <= maxShelves) hi = mid; // feasible: try smaller
    else lo = mid + 1;                              // infeasible: need more
  }
  return lo;
}

// minShelfCapacity([2, 3, 1, 2, 4, 3], 3) -> 6
// minShelfCapacity([1, 2, 3, 4, 5], 1)    -> 15
// minShelfCapacity([5, 5, 5], 3)          -> 5

function countRegions(grid) {
  if (grid.length === 0) return 0;
  const rows = grid.length, cols = grid[0].length;
  let regions = 0;

  const flood = (sr, sc) => {
    const queue = [[sr, sc]];
    grid[sr][sc] = 0;                 // mark seen by sinking the land
    while (queue.length) {
      const [r, c] = queue.shift();
      const neighbors = [[r-1,c],[r+1,c],[r,c-1],[r,c+1]];
      for (const [nr, nc] of neighbors) {
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc] === 1) {
          grid[nr][nc] = 0;           // mark before enqueue to avoid dupes
          queue.push([nr, nc]);
        }
      }
    }
  };

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (grid[r][c] === 1) {         // unvisited land -> new region
        regions++;
        flood(r, c);
      }
    }
  }
  return regions;
}

// countRegions([[1,1,0],[0,1,0],[0,0,1]]) -> 2
// countRegions([[0,0],[0,0]])             -> 0

function countWays(n, steps) {
  const memo = new Map();
  const ways = (remaining) => {
    if (remaining === 0) return 1;         // one way: take no more steps
    if (remaining < 0) return 0;           // overshot: dead end
    if (memo.has(remaining)) return memo.get(remaining);
    let total = 0;
    for (const s of steps) {
      total += ways(remaining - s);        // order matters -> sum all firsts
    }
    memo.set(remaining, total);
    return total;
  };
  return ways(n);
}

// countWays(4, [1, 2])    -> 5   (1111, 112, 121, 211, 22)
// countWays(3, [1, 2, 3]) -> 4   (111, 12, 21, 3)
// countWays(0, [1, 2])    -> 1
